import React, { useState, useEffect, useContext, useCallback } from 'react';
import { AuthContext } from '../context/AuthContext'; // Ensure this matches your context file
import api from '../api/axiosConfig';
import { Activity, Terminal, Zap, TrendingUp, TrendingDown, Wifi, WifiOff } from 'lucide-react';

const LiveMarketPage = () => {
    // 1. Context Access
    const { token } = useContext(AuthContext);

    // 2. State Management
    const [stocks, setStocks] = useState([]);
    const [logs, setLogs] = useState([]);
    const [isConnected, setIsConnected] = useState(false);
    const [lastPulse, setLastPulse] = useState(null);

    const addLog = useCallback((msg) => {
        const time = new Date().toLocaleTimeString();
        setLogs(prev => [`[${time}] ${msg}`, ...prev].slice(0, 10));
    }, []);

    // 3. Initialize Stocks from Portfolio History
    useEffect(() => {
        const fetchCurrentPortfolio = async () => {
            try {
                const res = await api.get('/portfolio/history');
                if (res.data.length > 0) {
                    const latest = res.data[0];
                    // Parse holdings if they are stored as a JSON string
                    const tickers = typeof latest.holdings === 'string' 
                        ? JSON.parse(latest.holdings) 
                        : latest.holdings;
                    
                    setStocks(tickers.map(t => ({
                        ticker: t,
                        price: Math.floor(Math.random() * 3000) + 500,
                        change: 0
                    })));
                }
            } catch (err) {
                addLog("VAULT_SYNC_ERROR: Unable to load latest holdings.");
            }
        };
        fetchCurrentPortfolio();
    }, [addLog]);

    // 4. WebSocket Lifecycle
    useEffect(() => {
        if (!token) {
            addLog("AUTH_ERROR: Missing access token. Re-login required.");
            return;
        }

        const ws = new WebSocket(`ws://localhost:8000/ws/pulse?token=${token}`);

        ws.onopen = () => {
            setIsConnected(true);
            addLog("NETWORK_LINK_ESTABLISHED: NODE_PUNE_01");
        };

        ws.onmessage = (event) => {
            const data = JSON.parse(event.data);
            setLastPulse(data.timestamp);
            addLog(`SYNC_PULSE: STATUS=${data.status} NODE=${data.node}`);
            
            // Simulation logic triggered by server heartbeat
            setStocks(prev => prev.map(s => {
                const move = (Math.random() - 0.5) * 6;
                return { 
                    ...s, 
                    price: parseFloat((s.price + move).toFixed(2)), 
                    change: parseFloat(move.toFixed(2)) 
                };
            }));
        };

        ws.onclose = () => {
            setIsConnected(false);
            addLog("CONNECTION_LOST: ATTEMPTING_HOT_SWAP...");
        };

        ws.onerror = () => {
            addLog("CRITICAL_NODE_FAILURE: WEBSOCKET_HANDSHAKE_REJECTED");
        };

        return () => ws.close();
    }, [token, addLog]);

    return (
        <div className="reveal-node" style={containerStyle}>
            {/* Header / Status Bar */}
            <div style={headerStyle}>
                <div style={{ display: 'flex', alignItems: 'center', gap: '15px' }}>
                    <div style={pulseCircle(isConnected)} />
                    <h1 style={titleStyle}>MARKET_PULSE_<span style={{color:'#10b981'}}>v2.0</span></h1>
                </div>
                <div style={statusTag(isConnected)}>
                    {isConnected ? <Wifi size={12}/> : <WifiOff size={12}/>}
                    {isConnected ? 'UPLINK_STABLE' : 'UPLINK_OFFLINE'}
                </div>
            </div>

            {/* Live Ticker Grid */}
            <div style={gridStyle}>
                {stocks.map((stock, i) => (
                    <div key={i} style={stockCardStyle(stock.change >= 0)}>
                        <div style={cardHeader}>
                            <span style={tickerText}>{stock.ticker}</span>
                            <Zap size={14} color={stock.change >= 0 ? "#10b981" : "#ef4444"} />
                        </div>
                        <div style={priceText}>₹{stock.price.toLocaleString()}</div>
                        <div style={changeText(stock.change >= 0)}>
                            {stock.change >= 0 ? <TrendingUp size={14}/> : <TrendingDown size={14}/>}
                            {stock.change >= 0 ? '+' : ''}{stock.change}%
                        </div>
                    </div>
                ))}
                {stocks.length === 0 && (
                    <div style={emptyState}>AWAITING_PORTFOLIO_INDEX...</div>
                )}
            </div>

            {/* Logs & Metadata */}
            <div style={bottomGrid}>
                <div style={terminalWrapper}>
                    <div style={terminalHeader}>
                        <Terminal size={14} /> SYSTEM_EXECUTION_FEED
                    </div>
                    <div style={logBox}>
                        {logs.map((log, i) => (
                            <div key={i} style={logLine(i)}>{log}</div>
                        ))}
                    </div>
                </div>

                <div style={metaCard}>
                    <p style={metaLabel}>LAST_HEARTBEAT_TS</p>
                    <p style={metaValue}>{lastPulse || 'AWAITING_SYNC...'}</p>
                    <div style={divider} />
                    <p style={metaLabel}>ACTIVE_NODE</p>
                    <p style={metaValue}>PUNE_TERMINAL_01</p>
                </div>
            </div>

            {/* Global Styles for Animations */}
            <style>{`
                @keyframes genPulse {
                    0% { transform: scale(1); opacity: 1; }
                    50% { transform: scale(1.2); opacity: 0.7; }
                    100% { transform: scale(1); opacity: 1; }
                }
                .reveal-node { animation: fadeIn 0.5s ease-out; }
                @keyframes fadeIn { from { opacity: 0; transform: translateY(10px); } to { opacity: 1; transform: translateY(0); } }
            `}</style>
        </div>
    );
};

/* --- Visual Styles --- */
const containerStyle = { padding: '2.5rem 1.5rem', maxWidth: '1200px', margin: '0 auto', display: 'flex', flexDirection: 'column', gap: '2rem' };
const headerStyle = { display: 'flex', justifyContent: 'space-between', alignItems: 'center', borderBottom: '1px solid #1a1d23', paddingBottom: '1.2rem' };
const titleStyle = { margin: 0, fontSize: '1.5rem', fontWeight: 900, letterSpacing: '-0.03em', color: '#fff' };

const pulseCircle = (active) => ({
    width: '12px', height: '12px', borderRadius: '50%', background: active ? '#10b981' : '#ef4444',
    boxShadow: active ? '0 0 12px #10b981' : 'none', animation: active ? 'genPulse 2s infinite' : 'none'
});

const statusTag = (online) => ({
    display: 'flex', alignItems: 'center', gap: '8px', padding: '6px 14px', borderRadius: '6px',
    fontSize: '0.65rem', fontWeight: 800, fontFamily: 'monospace', border: `1px solid ${online ? '#10b981' : '#ef4444'}`,
    color: online ? '#10b981' : '#ef4444', background: online ? 'rgba(16,185,129,0.05)' : 'rgba(239,68,68,0.05)'
});

const gridStyle = { display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(260px, 1fr))', gap: '1.5rem' };
const stockCardStyle = (up) => ({
    padding: '1.5rem', background: '#0d0f14', border: '1px solid #1a1d23',
    borderRadius: '20px', borderLeft: `4px solid ${up ? '#10b981' : '#ef4444'}`, transition: 'transform 0.2s ease'
});

const cardHeader = { display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '1rem' };
const tickerText = { fontSize: '0.75rem', fontWeight: 800, color: '#666', letterSpacing: '0.1em' };
const priceText = { fontSize: '2rem', fontWeight: 900, color: '#fff', fontFamily: 'monospace', marginBottom: '0.5rem' };
const changeText = (up) => ({ display: 'flex', alignItems: 'center', gap: '6px', fontSize: '0.85rem', fontWeight: 800, color: up ? '#10b981' : '#ef4444' });

const bottomGrid = { display: 'grid', gridTemplateColumns: '2fr 1fr', gap: '1.5rem' };
const terminalWrapper = { background: '#0a0b0e', borderRadius: '18px', border: '1px solid #1a1d23', overflow: 'hidden' };
const terminalHeader = { padding: '0.8rem 1.2rem', background: '#161b22', borderBottom: '1px solid #1a1d23', fontSize: '0.65rem', color: '#666', display: 'flex', alignItems: 'center', gap: '10px' };
const logBox = { padding: '1.2rem', height: '220px', overflowY: 'auto', display: 'flex', flexDirection: 'column', gap: '8px' };
const logLine = (i) => ({ fontSize: '0.75rem', fontFamily: 'monospace', color: i === 0 ? '#10b981' : '#888', opacity: i === 0 ? 1 : 0.6, paddingLeft: '10px', borderLeft: i === 0 ? '2px solid #10b981' : 'none' });

const metaCard = { padding: '1.5rem', background: '#0d0f14', border: '1px solid #1a1d23', borderRadius: '18px', display: 'flex', flexDirection: 'column', justifyContent: 'center' };
